mapper.select:
SELECT COUNT(*) 
FROM TBL_PROD_PRODINFO P
LEFT JOIN TBL_COM_GOODS G ON P.PARTNO = G.PARTNO

  1=1
  AND P.ENDDATE >= #{start_date}
  AND P.ENDDATE <= #{end_date}
  AND P.PLANTCD = #{plant_cd}
  AND P.PROCESSCD = #{process_cd}
  AND P.SHIFT = #{shift}

SELECT P.ENDDATE AS WORKDAY, CAST(P.REGUSERID AS VARCHAR) AS WORKER, P.PROCESSCD, P.LOTNO, P.PARTNO, G.PARTNM, '' AS CUSTOMPARTNO, G.UNIT, ISNULL(W.ORDQTY, 0) AS ORDQTY, ISNULL(P.LOTQTY, 0) AS PRODQTY, ISNULL(P.LOTQTY, 0) - ISNULL(F.TOT_FAILQTY, 0) AS GOODQTY, ISNULL(F.TOT_FAILQTY, 0) AS FAILQTY, ISNULL(P.RESULTGCODE, '') AS STATUS FROM TBL_PROD_PRODINFO P LEFT JOIN TBL_COM_GOODS G ON P.PARTNO = G.PARTNO LEFT JOIN TBL_PROD_WORKORDER W ON P.WORKORDNO = W.WORKORDNO LEFT JOIN ( SELECT LOTNO, SUM(FAILQTY) AS TOT_FAILQTY FROM TBL_PROD_FAILQTY GROUP BY LOTNO ) F ON P.LOTNO = F.LOTNO
1=1 AND P.ENDDATE >= #{start_date} AND P.ENDDATE <= #{end_date} AND P.PLANTCD = #{plant_cd} AND P.PROCESSCD = #{process_cd} AND P.SHIFT = #{shift}
ORDER BY P.ENDDATE DESC, P.LOTNO DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY
